<script>
  // Regular reactive variable
  let count = 0;
  let step = 1;

  // Reactive declaration — recalculates when count or step change
  $: doubled = count * 2;
  $: message = count === 0 ? 'Click to start' : `Count is ${count}`;

  // Reactive statement — runs side effects
  $: if (count > 10) {
    console.log('Count is getting high!');
  }

  // Array reactivity — must reassign, not mutate
  let items = ['apple', 'banana'];
  function addItem(fruit) {
    items = [...items, fruit]; // triggers update
    // items.push(fruit) would NOT trigger update!
  }

  function increment() {
    count += step; // direct assignment triggers reactivity
  }
</script>

<button on:click={increment}>+{step}</button>
<p>{message}</p>
<p>Doubled: {doubled}</p>
<ul>
  {#each items as item}
    <li>{item}</li>
  {/each}
</ul>
